import { ethers } from "ethers";
import { useState } from "react";

// 1. Import the entire JSON artifact
import CertificateVerifierArtifact from "./artifacts/contracts/Certificate.sol/CertificateVerifier.json";

// 2. Extract the ABI and the Deployed Address
const abi = CertificateVerifierArtifact.abi;
const contractAddress = "0x5FbDB2315678afecb367f032d93F642f64180aa3";

function App() {
  const [certId, setCertId] = useState("");
  const [result, setResult] = useState(null);

  async function verifyCertificate() {
    if (!window.ethereum) return alert("Please install MetaMask");
    
    const provider = new ethers.providers.Web3Provider(window.ethereum);
    const contractAddress = "0x5FbDB2315678afecb367f032d93F642f64180aa3";
    const abi = [ /* Your Contract ABI here */ ];
    
    const contract = new ethers.Contract(contractAddress, abi, provider);
    const bytes32Id = ethers.utils.formatBytes32String(certId);
    
    const data = await contract.verify(bytes32Id);
    setResult({ name: data[0], course: data[1], ipfs: data[2], valid: data[3] });
  }

  return (
    <div style={{ padding: "50px" }}>
      <h1>Academic Verifier</h1>
      <input placeholder="Enter Certificate ID" onChange={(e) => setCertId(e.target.value)} />
      <button onClick={verifyCertificate}>Verify on Blockchain</button>
      
      {result && result.valid && (
        <div style={{ marginTop: "20px", color: "green" }}>
          <p>Student: {result.name}</p>
          <p>Course: {result.course}</p>
          <a href={`https://ipfs.io/ipfs/${result.ipfs}`}>View Original Certificate</a>
        </div>
      )}
    </div>
  );
}
export default App;
